<?php require 'config.php'; if(isset($_SESSION['parent_email'])) { header('Location: index.php'); exit; } ?> <!DOCTYPE html> <html lang="en"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>GhostMonitor — Login</title> <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css"> <link href="https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet"> <style> *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; } :root { --bg: #0a0a0f; --surface: #111118; --border: rgba(255,255,255,0.07); --accent: #7c5cfc; --accent-glow: rgba(124, 92, 252, 0.35); --accent-soft: rgba(124, 92, 252, 0.12); --text: #f0eeff; --muted: #6b6880; --danger: #ff4d6d; --input-bg: rgba(255,255,255,0.04); --input-border: rgba(255,255,255,0.1); --input-focus: rgba(124, 92, 252, 0.5); } body { font-family: 'DM Sans', sans-serif; background: var(--bg); min-height: 100vh; display: flex; align-items: center; justify-content: center; color: var(--text); overflow: hidden; } /* Ambient background */ body::before { content: ''; position: fixed; width: 600px; height: 600px; background: radial-gradient(circle, rgba(124,92,252,0.15) 0%, transparent 70%); top: -200px; right: -200px; pointer-events: none; z-index: 0; } body::after { content: ''; position: fixed; width: 500px; height: 500px; background: radial-gradient(circle, rgba(90,60,200,0.1) 0%, transparent 70%); bottom: -150px; left: -150px; pointer-events: none; z-index: 0; } .login-wrap { position: relative; z-index: 1; width: 100%; max-width: 420px; padding: 1.5rem; animation: rise 0.6s cubic-bezier(0.16, 1, 0.3, 1) both; } @keyframes rise { from { opacity: 0; transform: translateY(24px); } to { opacity: 1; transform: translateY(0); } } .brand { display: flex; align-items: center; gap: 0.75rem; margin-bottom: 2.5rem; } .brand-icon { width: 44px; height: 44px; background: var(--accent); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 1.2rem; box-shadow: 0 0 24px var(--accent-glow); } .brand-text h1 { font-family: 'Syne', sans-serif; font-size: 1.25rem; font-weight: 700; letter-spacing: -0.02em; } .brand-text span { font-size: 0.75rem; color: var(--muted); letter-spacing: 0.05em; text-transform: uppercase; } .card { background: var(--surface); border: 1px solid var(--border); border-radius: 20px; padding: 2.5rem; box-shadow: 0 24px 80px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.03); } .card-title { font-family: 'Syne', sans-serif; font-size: 1.6rem; font-weight: 700; margin-bottom: 0.4rem; letter-spacing: -0.03em; } .card-sub { color: var(--muted); font-size: 0.875rem; margin-bottom: 2rem; } .field { margin-bottom: 1.25rem; } .field label { display: block; font-size: 0.8rem; font-weight: 500; color: var(--muted); margin-bottom: 0.5rem; letter-spacing: 0.03em; text-transform: uppercase; } .input-wrap { position: relative; } .input-wrap i { position: absolute; left: 1rem; top: 50%; transform: translateY(-50%); color: var(--muted); font-size: 0.9rem; pointer-events: none; transition: color 0.2s; } .input-wrap input { width: 100%; padding: 0.875rem 1rem 0.875rem 2.75rem; background: var(--input-bg); border: 1px solid var(--input-border); border-radius: 12px; color: var(--text); font-family: 'DM Sans', sans-serif; font-size: 0.95rem; outline: none; transition: border-color 0.2s, box-shadow 0.2s, background 0.2s; } .input-wrap input::placeholder { color: var(--muted); } .input-wrap input:focus { border-color: var(--accent); background: var(--accent-soft); box-shadow: 0 0 0 3px var(--accent-glow); } .input-wrap input:focus + i, .input-wrap:has(input:focus) i { color: var(--accent); } /* Flip icon order for proper z-stacking */ .input-wrap i { z-index: 1; } .btn-login { width: 100%; padding: 0.9rem; margin-top: 0.5rem; background: var(--accent); color: #fff; border: none; border-radius: 12px; font-family: 'Syne', sans-serif; font-size: 1rem; font-weight: 600; cursor: pointer; letter-spacing: 0.02em; display: flex; align-items: center; justify-content: center; gap: 0.5rem; transition: transform 0.15s, box-shadow 0.15s, filter 0.15s; box-shadow: 0 4px 20px var(--accent-glow); } .btn-login:hover { transform: translateY(-1px); box-shadow: 0 8px 30px var(--accent-glow); filter: brightness(1.08); } .btn-login:active { transform: translateY(0); } .btn-login.loading .label { display: none; } .btn-login .spinner { display: none; } .btn-login.loading .spinner { display: inline-block; width: 18px; height: 18px; border: 2px solid rgba(255,255,255,0.3); border-top-color: #fff; border-radius: 50%; animation: spin 0.7s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } } .error-msg { background: rgba(255,77,109,0.12); border: 1px solid rgba(255,77,109,0.3); color: #ff8099; font-size: 0.85rem; padding: 0.75rem 1rem; border-radius: 10px; margin-bottom: 1rem; display: none; } .divider { margin: 1.75rem 0 1.25rem; border: none; border-top: 1px solid var(--border); } .footer-links { display: flex; justify-content: space-between; font-size: 0.82rem; color: var(--muted); } .footer-links a { color: var(--accent); text-decoration: none; font-weight: 500; transition: opacity 0.2s; } .footer-links a:hover { opacity: 0.75; } @media (max-width: 480px) { .card { padding: 1.75rem; } .footer-links { flex-direction: column; gap: 0.5rem; } } </style> </head> <body> <div class="login-wrap"> <div class="brand"> <div class="brand-icon"><i class="fas fa-ghost"></i></div> <div class="brand-text"> <h1>GhostMonitor</h1> <span>Parental Control</span> </div> </div> <div class="card"> <h2 class="card-title">Welcome back</h2> <p class="card-sub">Sign in to your monitoring dashboard</p> <div class="error-msg" id="errorMsg"></div> <form id="loginForm" novalidate> <div class="field"> <label>Email address</label> <div class="input-wrap"> <i class="fas fa-envelope"></i> <input type="email" id="email" placeholder="you@example.com" required> </div> </div> <div class="field"> <label>Password</label> <div class="input-wrap"> <i class="fas fa-lock"></i> <input type="password" id="password" placeholder="••••••••" required> </div> </div> <button type="submit" class="btn-login" id="loginBtn"> <span class="label">Sign in <i class="fas fa-arrow-right" style="font-size:0.85rem"></i></span> <span class="spinner"></span> </button> </form> <hr class="divider"> <div class="footer-links"> <span>Forgot password? <a href="mailto:<?php echo ADMIN_EMAIL; ?>">Contact admin</a></span> <span><a href="mailto:<?php echo ADMIN_EMAIL; ?>?subject=GhostMonitor Access Request&body=Hi, I would like to request access to GhostMonitor.">Request access</a></span> </div> </div> </div> <script> const form = document.getElementById('loginForm'); const btn = document.getElementById('loginBtn'); const err = document.getElementById('errorMsg'); form.addEventListener('submit', async (e) => { e.preventDefault(); err.style.display = 'none'; btn.classList.add('loading'); const email = document.getElementById('email').value; const password = document.getElementById('password').value; try { const res = await fetch('api/auth.php', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ email, password }) }); const data = await res.json(); if (data.success) { window.location.href = 'index.php'; } else { err.textContent = data.message || 'Invalid credentials. Please try again.'; err.style.display = 'block'; btn.classList.remove('loading'); } } catch { err.textContent = 'Connection error. Please contact admin.'; err.style.display = 'block'; btn.classList.remove('loading'); } }); </script> </body> </html>